import React, { useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { Phone, ArrowRight, Loader } from 'lucide-react';
import { authAPI } from '../services/api';
import {
  loginWithOtp,
  setOtpSent,
  clearError,
} from '../store/slices/authslice';

const LoginPage = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const dispatch = useDispatch();
  const { loading, error, otpSent } = useSelector((state) => state.auth);

  const [phone, setPhone] = useState('');
  const [otp, setOtp] = useState('');
  const [sendingOtp, setSendingOtp] = useState(false);

  const from = location.state?.from?.pathname || '/';

  const handleSendOtp = async (e) => {
    e.preventDefault();
    if (!phone.match(/^[0-9]{10}$/)) return;

    setSendingOtp(true);
    try {
      // Send the request directly to our Django backend
      await authAPI.sendOtp({ phone });

      // If it succeeds, update Redux so the UI changes to the OTP input view
      dispatch(setOtpSent(true));
      dispatch(clearError());
    } catch (err) {
      console.error("Failed to send OTP", err);
    } finally {
      setSendingOtp(false);
    }
  };

  const handleVerify = async (e) => {
    e.preventDefault();
    if (otp.length !== 6) return;

    const resultAction = await dispatch(loginWithOtp({ phone, otp }));

    // Check if the Thunk successfully executed
    if (loginWithOtp.fulfilled.match(resultAction)) {
      // If successful, take them back to where they were, or home
      navigate(from, { replace: true });
    }
  };

  return (
    <div className="min-h-[80vh] flex items-center justify-center bg-gray-50 py-12 px-4">
      <div className="max-w-md w-full space-y-8 bg-white p-8 rounded-2xl shadow-sm border border-gray-100">
        <div className="text-center">
          <h2 className="text-3xl font-bold text-gray-900">Welcome Back</h2>
          <p className="mt-2 text-sm text-gray-600">
            Login with your phone number
          </p>
        </div>

        {!otpSent ? (
          <form onSubmit={handleSendOtp} className="mt-8 space-y-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Phone Number
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-500">
                  +91
                </div>
                <input
                  type="tel"
                  placeholder="9876543210"
                  maxLength={10}
                  className="pl-12 w-full px-4 py-3 border border-gray-200 rounded-lg focus:ring-2 focus:ring-primary-500 transition outline-none"
                  value={phone}
                  onChange={(e) => setPhone(e.target.value.replace(/\D/g, ''))}
                  required
                />
              </div>
            </div>

            {error && (
              <p className="text-sm text-red-600 text-center">{error}</p>
            )}

            <button
              type="submit"
              disabled={sendingOtp || phone.length !== 10}
              className="w-full bg-primary-700 text-white py-3 rounded-lg font-bold hover:bg-primary-800 transition disabled:opacity-70 flex items-center justify-center gap-2"
            >
              {sendingOtp ? (
                <Loader className="w-5 h-5 animate-spin" />
              ) : (
                <>
                  Send OTP <ArrowRight className="w-4 h-4" />
                </>
              )}
            </button>
          </form>
        ) : (
          <form onSubmit={handleVerify} className="mt-8 space-y-6">
            <div className="text-center">
              <p className="text-sm text-gray-600">Enter the OTP sent to</p>
              <p className="font-bold text-gray-900">+91 {phone}</p>
            </div>

            <div>
              <input
                type="text"
                placeholder="123456"
                maxLength={6}
                className="w-full px-4 py-3 border border-gray-200 rounded-lg text-center text-2xl tracking-[0.5em] font-bold focus:ring-2 focus:ring-primary-500 outline-none"
                value={otp}
                onChange={(e) => setOtp(e.target.value.replace(/\D/g, ''))}
                required
              />
            </div>

            {error && (
              <p className="text-sm text-red-600 text-center">{error}</p>
            )}

            <button
              type="submit"
              disabled={loading || otp.length !== 6}
              className="w-full bg-primary-700 text-white py-3 rounded-lg font-bold hover:bg-primary-800 transition disabled:opacity-70 flex items-center justify-center"
            >
              {loading ? (
                <Loader className="w-5 h-5 animate-spin" />
              ) : (
                'Verify & Login'
              )}
            </button>

            <button
              type="button"
              onClick={() => {
                dispatch(setOtpSent(false));
                setOtp('');
              }}
              className="w-full text-sm text-primary-600 hover:underline font-medium"
            >
              Change Phone Number
            </button>
          </form>
        )}
      </div>
    </div>
  );
};

export default LoginPage;
